<span class="line"><span style="color:#CDD6F4;">            permission_gate</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> PermissionGate</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">config</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">permission_level</span><span style="color:#9399B2;">),</span></span>
